1	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
2	import { guild, generateId } from '@shardworks/nexus-core';
3	import type { StacksApi, Book, WhereClause } from '@shardworks/stacks-apparatus';
4	
5	import type {
6	  ClickDoc,
7	  ClickLinkDoc,
8	  ClickLinks,
9	  ClickStatus,
10	  ClickFilters,
11	  ClickTree,
12	  LinkType,
13	  RatchetApi,
14	  CreateClickRequest,
15	  ConcludeClickRequest,
16	  DropClickRequest,
17	  ReparentClickRequest,
18	  LinkClickRequest,
19	  UnlinkClickRequest,
20	  ExtractClickRequest,
21	} from './types.ts';
22	
23	import {
24	  clickCreate,
25	  clickShow,
26	  clickList,
27	  clickPark,
28	  clickResume,
29	  clickConclude,
30	  clickDrop,
31	  clickReparent,
32	  clickLink,
33	  clickUnlink,
34	  clickExtract,
35	} from './tools/index.ts';
36	
37	// ── Status machine ──────────────────────────────────────────────────
38	
39	const ALLOWED_FROM: Record<ClickStatus, ClickStatus[]> = {
40	  live:      ['parked'],
41	  parked:    ['live'],
42	  concluded: ['live', 'parked'],
43	  dropped:   ['live', 'parked'],
44	};
45	
46	const TERMINAL_STATUSES = new Set<ClickStatus>(['concluded', 'dropped']);
47	
48	const VALID_LINK_TYPES = new Set<string>(['related', 'commissioned', 'supersedes', 'depends-on']);
49	
50	// ── Factory ─────────────────────────────────────────────────────────
51	
52	export function createRatchet(): Plugin {
53	  let stacks: StacksApi;
54	  let clicks: Book<ClickDoc>;
55	  let clickLinks: Book<ClickLinkDoc>;
56	
57	  // ── Helpers ─────────────────────────────────────────────────────
58	
59	  function validateTransition(click: ClickDoc, target: ClickStatus): void {
60	    const allowed = ALLOWED_FROM[target];
61	    if (!allowed || !allowed.includes(click.status)) {
62	      throw new Error(
63	        `Cannot transition click "${click.id}" to "${target}": status is "${click.status}", expected one of: ${allowed?.join(', ') ?? 'none'}.`,
64	      );
65	    }
66	  }
67	
68	  function buildWhereClause(filters?: ClickFilters): WhereClause | { or: WhereClause[] } | undefined {
69	    if (!filters) return undefined;
70	    const clauses: WhereClause = [];
71	
72	    if (filters.status !== undefined) {
73	      if (Array.isArray(filters.status)) {
74	        if (filters.status.length === 1) {
75	          clauses.push(['status', '=', filters.status[0]]);
76	        } else if (filters.status.length > 1) {
77	          return {
78	            or: filters.status.map((s) => {
79	              const c: WhereClause = [['status', '=', s]];
80	              if (filters.parentId !== undefined) c.push(['parentId', '=', filters.parentId]);
81	              return c;
82	            }),
83	          };
84	        }
85	      } else {
86	        clauses.push(['status', '=', filters.status]);
87	      }
88	    }
89	
90	    if (filters.parentId !== undefined) {
91	      clauses.push(['parentId', '=', filters.parentId]);
92	    }
93	
94	    return clauses.length > 0 ? clauses : undefined;
95	  }
96	
97	  async function buildTree(clickId: string): Promise<ClickTree> {
98	    const click = await api.get(clickId);
99	    const children = await clicks.find({ where: [['parentId', '=', clickId]] });
100	    const childTrees: ClickTree[] = [];
101	    // Sort children by createdAt ascending
102	    children.sort((a, b) => a.createdAt.localeCompare(b.createdAt));
103	    for (const child of children) {
104	      childTrees.push(await buildTree(child.id));
105	    }
106	    return { click, children: childTrees };
107	  }
108	
109	  function renderMarkdown(tree: ClickTree, depth: number = 0): string {
110	    const lines: string[] = [];
111	    const click = tree.click;
112	
113	    // Heading or bold
114	    if (depth <= 5) {
115	      const prefix = '#'.repeat(depth + 1);
116	      lines.push(`${prefix} ${click.id} [${click.status}]`);
117	    } else {
118	      lines.push(`**${click.id} [${click.status}]**`);
119	    }
120	
121	    lines.push(`> ${click.goal}`);
122	    lines.push(`Status: ${click.status}`);
123	    if (click.conclusion !== undefined) lines.push(`Conclusion: ${click.conclusion}`);
124	    if (click.createdSessionId !== undefined) lines.push(`Created by: ${click.createdSessionId}`);
125	    if (click.resolvedSessionId !== undefined) lines.push(`Resolved by: ${click.resolvedSessionId}`);
126	    lines.push(`Created: ${click.createdAt}`);
127	    if (click.resolvedAt !== undefined) lines.push(`Resolved: ${click.resolvedAt}`);
128	
129	    for (const child of tree.children) {
130	      lines.push('');
131	      lines.push(renderMarkdown(child, depth + 1));
132	    }
133	
134	    return lines.join('\n');
135	  }
136	
137	  // ── API ─────────────────────────────────────────────────────────
138	
139	  const api: RatchetApi = {
140	    async create(params: CreateClickRequest): Promise<ClickDoc> {
141	      const id = generateId('c', 6);
142	      const doc: ClickDoc = {
143	        id,
144	        goal: params.goal,
145	        status: 'live',
146	        createdAt: new Date().toISOString(),
147	        parentId: params.parentId,
148	        createdSessionId: params.createdSessionId,
149	      };
150	
151	      if (params.parentId) {
152	        await stacks.transaction(async (tx) => {
153	          const txClicks = tx.book<ClickDoc>('ratchet', 'clicks');
154	          const parent = await txClicks.get(params.parentId!);
155	          if (!parent) throw new Error(`Click "${params.parentId}" not found.`);
156	          await txClicks.put(doc);
157	        });
158	      } else {
159	        await clicks.put(doc);
160	      }
161	
162	      return doc;
163	    },
164	
165	    async get(id: string): Promise<ClickDoc> {
166	      const click = await clicks.get(id);
167	      if (!click) throw new Error(`Click "${id}" not found.`);
168	      return click;
169	    },
170	
171	    async list(filters?: ClickFilters): Promise<ClickDoc[]> {
172	      const limit = filters?.limit ?? 20;
173	      const offset = filters?.offset;
174	      const where = buildWhereClause(filters);
175	
176	      return clicks.find({
177	        where: where as WhereClause,
178	        limit,
179	        offset,
180	        orderBy: [['createdAt', 'desc']],
181	      });
182	    },
183	
184	    async park(id: string): Promise<ClickDoc> {
185	      const click = await api.get(id);
186	      validateTransition(click, 'parked');
187	      return clicks.patch(id, { status: 'parked' });
188	    },
189	
190	    async resume(id: string): Promise<ClickDoc> {
191	      const click = await api.get(id);
192	      validateTransition(click, 'live');
193	      return clicks.patch(id, { status: 'live' });
194	    },
195	
196	    async conclude(id: string, params: ConcludeClickRequest): Promise<ClickDoc> {
197	      if (!params.conclusion || params.conclusion.trim() === '') {
198	        throw new Error('Conclusion must be a non-empty string.');
199	      }
200	      const click = await api.get(id);
201	      validateTransition(click, 'concluded');
202	      if (click.conclusion !== undefined) {
203	        throw new Error(`Click "${id}" already has a conclusion set.`);
204	      }
205	      const patch: Partial<ClickDoc> = {
206	        status: 'concluded',
207	        conclusion: params.conclusion,
208	        resolvedAt: new Date().toISOString(),
209	      };
210	      if (params.resolvedSessionId) {
211	        patch.resolvedSessionId = params.resolvedSessionId;
212	      }
213	      return clicks.patch(id, patch);
214	    },
215	
216	    async drop(id: string, params: DropClickRequest): Promise<ClickDoc> {
217	      if (!params.conclusion || params.conclusion.trim() === '') {
218	        throw new Error('Conclusion must be a non-empty string.');
219	      }
220	      const click = await api.get(id);
221	      validateTransition(click, 'dropped');
222	      if (click.conclusion !== undefined) {
223	        throw new Error(`Click "${id}" already has a conclusion set.`);
224	      }
225	      const patch: Partial<ClickDoc> = {
226	        status: 'dropped',
227	        conclusion: params.conclusion,
228	        resolvedAt: new Date().toISOString(),
229	      };
230	      if (params.resolvedSessionId) {
231	        patch.resolvedSessionId = params.resolvedSessionId;
232	      }
233	      return clicks.patch(id, patch);
234	    },
235	
236	    async reparent(id: string, params: ReparentClickRequest): Promise<ClickDoc> {
237	      if (params.parentId === null || params.parentId === undefined) {
238	        // Move to root
239	        return clicks.patch(id, { parentId: undefined });
240	      }
241	
242	      const newParentId = params.parentId;
243	      return stacks.transaction(async (tx) => {
244	        const txClicks = tx.book<ClickDoc>('ratchet', 'clicks');
245	
246	        const click = await txClicks.get(id);
247	        if (!click) throw new Error(`Click "${id}" not found.`);
248	
249	        const parent = await txClicks.get(newParentId);
250	        if (!parent) throw new Error(`Click "${newParentId}" not found.`);
251	
252	        // Walk ancestor chain to detect circular parentage
253	        let current: ClickDoc | null = parent;
254	        while (current && current.parentId) {
255	          if (current.parentId === id) {
256	            throw new Error(`Cannot reparent click "${id}" under "${newParentId}": circular parentage detected.`);
257	          }
258	          current = await txClicks.get(current.parentId);
259	        }
260	
261	        // Also check if the new parent IS the click being reparented
262	        if (newParentId === id) {
263	          throw new Error(`Cannot reparent click "${id}" under "${newParentId}": circular parentage detected.`);
264	        }
265	
266	        await txClicks.patch(id, { parentId: newParentId });
267	        const updated = await txClicks.get(id);
268	        return updated!;
269	      });
270	    },
271	
272	    async link(params: LinkClickRequest): Promise<ClickLinkDoc> {
273	      if (!VALID_LINK_TYPES.has(params.linkType)) {
274	        throw new Error(`Invalid link type "${params.linkType}". Must be one of: related, commissioned, supersedes, depends-on.`);
275	      }
276	      if (params.sourceId === params.targetId) {
277	        throw new Error(`Cannot link a click to itself: "${params.sourceId}".`);
278	      }
279	
280	      const sourceIsClick = params.sourceId.startsWith('c-');
281	      const targetIsClick = params.targetId.startsWith('c-');
282	
283	      // Same-substrate: validate both exist
284	      if (sourceIsClick && targetIsClick) {
285	        const [source, target] = await Promise.all([
286	          clicks.get(params.sourceId),
287	          clicks.get(params.targetId),
288	        ]);
289	        if (!source) throw new Error(`Click "${params.sourceId}" not found.`);
290	        if (!target) throw new Error(`Click "${params.targetId}" not found.`);
291	      } else if (sourceIsClick) {
292	        // Cross-substrate: validate source click exists
293	        const source = await clicks.get(params.sourceId);
294	        if (!source) throw new Error(`Click "${params.sourceId}" not found.`);
295	      }
296	
297	      const compositeId = `${params.sourceId}:${params.targetId}:${params.linkType}`;
298	
299	      // Idempotent check
300	      const existing = await clickLinks.get(compositeId);
301	      if (existing) return existing;
302	
303	      const doc: ClickLinkDoc = {
304	        id: compositeId,
305	        sourceId: params.sourceId,
306	        targetId: params.targetId,
307	        linkType: params.linkType as ClickLinkDoc['linkType'],
308	        createdAt: new Date().toISOString(),
309	      };
310	      await clickLinks.put(doc);
311	      return doc;
312	    },
313	
314	    async unlink(params: UnlinkClickRequest): Promise<void> {
315	      const compositeId = `${params.sourceId}:${params.targetId}:${params.linkType}`;
316	      const existing = await clickLinks.get(compositeId);
317	      if (!existing) throw new Error(`Link "${compositeId}" not found.`);
318	      await clickLinks.delete(compositeId);
319	    },
320	
321	    async extract(rootId: string, params: ExtractClickRequest): Promise<string | ClickTree> {
322	      const tree = await buildTree(rootId);
323	      if (params.format === 'json') return tree;
324	      return renderMarkdown(tree);
325	    },
326	
327	    async resolveId(prefix: string): Promise<string> {
328	      const results = await clicks.find({ where: [['id', 'LIKE', prefix + '%']] });
329	      if (results.length === 0) {
330	        throw new Error(`No click found matching prefix "${prefix}".`);
331	      }
332	      if (results.length > 1) {
333	        throw new Error(`Ambiguous prefix "${prefix}": matches ${results.length} clicks.`);
334	      }
335	      return results[0].id;
336	    },
337	
338	    async links(clickId: string): Promise<ClickLinks> {
339	      const [outbound, inbound] = await Promise.all([
340	        clickLinks.find({ where: [['sourceId', '=', clickId]] }),
341	        clickLinks.find({ where: [['targetId', '=', clickId]] }),
342	      ]);
343	      return { outbound, inbound };
344	    },
345	  };
346	
347	  // ── Plugin ────────────────────────────────────────────────────────
348	
349	  return {
350	    apparatus: {
351	      requires: ['stacks'],
352	      recommends: ['oculus'],
353	
354	      supportKit: {
355	        books: {
356	          clicks: {
357	            indexes: ['status', 'createdAt', 'parentId', ['status', 'createdAt'], ['parentId', 'status']],
358	          },
359	          click_links: {
360	            indexes: ['sourceId', 'targetId', 'linkType', ['sourceId', 'linkType'], ['targetId', 'linkType']],
361	          },
362	        },
363	        tools: [
364	          clickCreate,
365	          clickShow,
366	          clickList,
367	          clickPark,
368	          clickResume,
369	          clickConclude,
370	          clickDrop,
371	          clickReparent,
372	          clickLink,
373	          clickUnlink,
374	          clickExtract,
375	        ],
376	      },
377	
378	      provides: api,
379	
380	      async start(_ctx: StartupContext): Promise<void> {
381	        const g = guild();
382	        stacks = g.apparatus<StacksApi>('stacks');
383	        clicks = stacks.book<ClickDoc>('ratchet', 'clicks');
384	        clickLinks = stacks.book<ClickLinkDoc>('ratchet', 'click_links');
385	      },
386	    },
387	  };
388	}
