    offset: z.number().optional().describe('Number of results to skip'),
  },
  permission: 'read',
  handler: async (params) => {
    const ratchet = guild().apparatus<RatchetApi>('ratchet');
    return ratchet.list({
      status: params.status,
      parentId: params.parentId,
      limit: params.limit,
      offset: params.offset,
    });
  },
});

