nsg writ list --type quest --limit 200 2>&1 | node -e "
const data = JSON.parse(require('fs').readFileSync('/dev/stdin','utf8'));
const byStatus = {};
for (const w of data) {
  byStatus[w.status] = (byStatus[w.status]||0) + 1;
}
console.log('Total:', data.length);
console.log('By status:', JSON.stringify(byStatus, null, 2));
console.log();
// Show open ones
const open = data.filter(w => !['completed','cancelled','failed'].includes(w.status));
for (const w of open) {
  console.log(\`[\${w.status}] \${w.id}  \${w.title}\`);
  if (w.parentId) console.log(\`        parent: \${w.parentId}\`);
}
"

nsg writ list --type quest --limit 200 2>&1 | node -e "
const data = JSON.parse(require('fs').readFileSync('/dev/stdin','utf8'));
const open = data.filter(w => !['completed','cancelled','failed'].includes(w.status));
const roots = open.filter(w => !w.parentId);
const childrenOf = (id) => open.filter(w => w.parentId === id);

function printTree(w, depth=0) {
  const indent = '  '.repeat(depth);
  const childCount = childrenOf(w.id).length;
  const suffix = childCount > 0 ? \` (\${childCount} children)\` : '';
  console.log(\`\${indent}[\${w.status}] \${w.id}\`);
  console.log(\`\${indent}  \${w.title}\${suffix}\`);
  for (const c of childrenOf(w.id)) {
    printTree(c, depth+1);
  }
}

console.log(\`\${roots.length} root quests, \${open.length} total open\n\`);
for (const r of roots) { printTree(r); console.log(); }
"

